  1→"use client";
  2→
  3→import { useState } from "react";
  4→import Link from "next/link";
  5→import { motion } from "framer-motion";
  6→import { ChevronRight, Search } from "lucide-react";
  7→import { categories } from "@/data/products";
  8→
  9→const containerVariants = {
 10→  hidden: {},
 11→  visible: {
 12→    transition: {
 13→      staggerChildren: 0.06,
 14→    },
 15→  },
 16→};
 17→
 18→const cardVariants = {
 19→  hidden: { opacity: 0, y: 24 },
 20→  visible: {
 21→    opacity: 1,
 22→    y: 0,
 23→    transition: { duration: 0.5, ease: "easeOut" as const },
 24→  },
 25→};
 26→
 27→export default function ProductsPage() {
 28→  const [search, setSearch] = useState("");
 29→
 30→  const filtered = categories.filter(
 31→    (cat) =>
 32→      cat.name.toLowerCase().includes(search.toLowerCase()) ||
 33→      cat.description.toLowerCase().includes(search.toLowerCase())
 34→  );
 35→
 36→  return (
 37→    <>
 38→      {/* Hero Banner */}
 39→      <section className="relative bg-gradient-to-br from-[#0F1D2F] via-[#1A2D44] to-[#0a1729] px-4 py-16 sm:py-20">
 40→        <div className="pointer-events-none absolute inset-0 overflow-hidden">
 41→          <div className="absolute -right-24 -top-24 h-72 w-72 rounded-full bg-white/5" />
 42→          <div className="absolute -bottom-16 -left-16 h-56 w-56 rounded-full bg-white/5" />
 43→        </div>
 44→        <div className="relative z-10 mx-auto max-w-7xl">
 45→          <motion.nav
 46→            initial={{ opacity: 0 }}
 47→            animate={{ opacity: 1 }}
 48→            transition={{ duration: 0.4 }}
 49→            aria-label="Breadcrumb"
 50→            className="mb-4 flex items-center gap-1.5 text-sm text-white/60"
 51→          >
 52→            <Link href="/" className="transition-colors hover:text-white">
 53→              Home
 54→            </Link>
 55→            <ChevronRight className="h-3.5 w-3.5" />
 56→            <span className="text-white">Products</span>
 57→          </motion.nav>
 58→          <motion.h1
 59→            initial={{ opacity: 0, y: 20 }}
 60→            animate={{ opacity: 1, y: 0 }}
 61→            transition={{ duration: 0.6 }}
 62→            className="text-4xl font-extrabold tracking-tight text-white sm:text-5xl"
 63→          >
 64→            Our Products
 65→          </motion.h1>
 66→          <motion.p
 67→            initial={{ opacity: 0, y: 20 }}
 68→            animate={{ opacity: 1, y: 0 }}
 69→            transition={{ duration: 0.6, delay: 0.15 }}
 70→            className="mt-3 max-w-2xl text-lg text-white/80"
 71→          >
 72→            Explore our full range of promotional and corporate merchandise,
 73→            curated for Australian businesses.
 74→          </motion.p>
 75→        </div>
 76→      </section>
 77→
 78→      {/* Search + Category Grid */}
 79→      <section className="bg-gradient-to-br from-[#B4A0F4] via-[#D8D0FC] to-[#B4A0F4] px-4 py-12 sm:py-16 lg:py-20">
 80→        <div className="mx-auto max-w-7xl">
 81→          {/* Search Bar */}
 82→          <div className="mx-auto mb-10 max-w-xl">
 83→            <div className="relative">
 84→              <Search className="absolute left-4 top-1/2 h-5 w-5 -translate-y-1/2 text-slate-400" />
 85→              <input
 86→                type="text"
 87→                value={search}
 88→                onChange={(e) => setSearch(e.target.value)}
 89→                placeholder="Search categories..."
 90→                className="w-full rounded-xl border border-slate-200 bg-white py-3 pl-12 pr-4 text-sm text-slate-700 shadow-sm outline-none transition-all placeholder:text-slate-400 focus:border-[#7C3AED] focus:ring-2 focus:ring-[#7C3AED]/20"
 91→              />
 92→            </div>
 93→          </div>
 94→
 95→          {/* Categories Grid */}
 96→          <motion.div
 97→            variants={containerVariants}
 98→            initial="hidden"
 99→            animate="visible"
100→            className="grid grid-cols-1 gap-5 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4"
101→          >
102→            {filtered.map((cat) => (
103→              <motion.div key={cat.slug} variants={cardVariants}>
104→                <Link
105→                  href={`/products/${cat.slug}`}
106→                  className="group block overflow-hidden rounded-2xl border border-slate-100 bg-white shadow-sm transition-all hover:shadow-lg hover:shadow-black/5"
107→                >
108→                  {/* Image */}
109→                  <div className="relative aspect-[4/3] overflow-hidden bg-slate-100">
110→                    {/* eslint-disable-next-line @next/next/no-img-element */}
111→                    <img
112→                      src={cat.image}
113→                      alt={cat.name}
114→                      style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }}
115→                      className="transition-transform duration-500 group-hover:scale-110"
116→                    />
117→                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent" />
118→                    <span className="absolute bottom-3 right-3 rounded-full bg-white/20 px-2.5 py-1 text-xs font-medium text-white backdrop-blur-sm">
119→                      {cat.productCount} products
120→                    </span>
121→                  </div>
122→
123→                  {/* Content */}
124→                  <div className="p-5">
125→                    <h3 className="text-base font-bold text-slate-900 transition-colors group-hover:text-[#7C3AED]">
126→                      {cat.name}
127→                    </h3>
128→                    <p className="mt-1.5 line-clamp-2 text-sm leading-relaxed text-slate-500">
129→                      {cat.description}
130→                    </p>
131→                  </div>
132→                </Link>
133→              </motion.div>
134→            ))}
135→          </motion.div>
136→
137→          {filtered.length === 0 && (
138→            <div className="py-16 text-center">
139→              <p className="text-lg font-medium text-slate-400">
140→                No categories match your search.
141→              </p>
142→            </div>
143→          )}
144→        </div>
145→      </section>
146→    </>
147→  );
148→}
149→

 1→export interface Product {
 2→  id: number;
 3→  name: string;
 4→  slug: string;
 5→  description: string;
 6→  category: string;
 7→  categorySlug: string;
 8→  image: string;
 9→  isNew?: boolean;
10→  isOnSale?: boolean;
11→  salePercent?: number;
12→  isSustainable?: boolean;
13→  collections?: string[];
14→}
15→
16→export interface Category {
17→  name: string;
18→  slug: string;
19→  description: string;
20→  image: string;
21→  productCount: number;
22→}
23→
24→export interface Collection {
25→  name: string;
26→  slug: string;
27→  description: string;
28→  image: string;
29→  productSlugs: string[];
30→  icon: string;
31→}
