  1→"use client";
  2→
  3→import { useState, useEffect } from "react";
  4→import Link from "next/link";
  5→import Image from "next/image";
  6→import { Phone, Mail, Clock, Search, Menu, X, ChevronDown, ShoppingBag } from "lucide-react";
  7→import { motion, AnimatePresence } from "framer-motion";
  8→import { categories } from "@/data/products";
  9→import { siteConfig } from "@/data/content";
 10→import { useQuoteCart } from "@/contexts/QuoteCartContext";
 11→
 12→export default function Header() {
 13→  const [isScrolled, setIsScrolled] = useState(false);
 14→  const [mobileOpen, setMobileOpen] = useState(false);
 15→  const [productsOpen, setProductsOpen] = useState(false);
 16→  const [mobileProductsOpen, setMobileProductsOpen] = useState(false);
 17→  const [searchOpen, setSearchOpen] = useState(false);
 18→  const { totalItems, openDrawer } = useQuoteCart();
 19→
 20→  useEffect(() => {
 21→    const onScroll = () => setIsScrolled(window.scrollY > 10);
 22→    window.addEventListener("scroll", onScroll);
 23→    return () => window.removeEventListener("scroll", onScroll);
 24→  }, []);
 25→
 26→  useEffect(() => {
 27→    if (mobileOpen) {
 28→      document.body.style.overflow = "hidden";
 29→    } else {
 30→      document.body.style.overflow = "";
 31→    }
 32→    return () => {
 33→      document.body.style.overflow = "";
 34→    };
 35→  }, [mobileOpen]);
 36→
 37→  const navLinks = [
 38→    { label: "Home", href: "/" },
 39→    { label: "Products", href: "/products", hasDropdown: true },
 40→    { label: "Collections", href: "/collections" },
 41→    { label: "New", href: "/new" },
 42→    { label: "Sale", href: "/sale" },
 43→    { label: "Kitting", href: "/kitting" },
 44→    { label: "About", href: "/about" },
 45→    { label: "Contact", href: "/contact" },
 46→  ];
 47→
 48→  return (
 49→    <header
 50→      className={`sticky top-0 z-50 w-full transition-shadow duration-300 ${
 51→        isScrolled ? "shadow-lg shadow-black/8" : ""
 52→      }`}
 53→    >
 54→      {/* Top Bar */}
 55→      <div className="bg-gradient-to-r from-[#B71C1C] via-[#5B21B6] to-[#B71C1C] text-white">
 56→        <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-2.5 text-xs sm:text-sm">
 57→          <div className="flex items-center gap-4 sm:gap-6">
 58→            <a
 59→              href={`tel:${siteConfig.phone.replace(/\s/g, "")}`}
 60→              className="flex items-center gap-1.5 transition-colors hover:text-[#7C3AED]"
 61→            >
 62→              <Phone className="h-3.5 w-3.5" />
 63→              <span className="hidden sm:inline">{siteConfig.phone}</span>
 64→            </a>
 65→            <a
 66→              href={`mailto:${siteConfig.email}`}
 67→              className="flex items-center gap-1.5 transition-colors hover:text-[#7C3AED]"
 68→            >
 69→              <Mail className="h-3.5 w-3.5" />
 70→              <span className="hidden sm:inline">{siteConfig.email}</span>
 71→            </a>
 72→          </div>
 73→          <div className="flex items-center gap-1.5 text-white/70">
 74→            <Clock className="h-3.5 w-3.5" />
 75→            <span className="hidden md:inline">{siteConfig.hours}</span>
 76→            <span className="md:hidden">Mon-Fri 8:30-5:00</span>
 77→          </div>
 78→        </div>
 79→      </div>
 80→
 81→      {/* Main Header */}
 82→      <div className="bg-gradient-to-r from-[#C4B5FD] via-[#EDE9FE] to-[#C4B5FD]">
 83→        <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-3 lg:py-4">
 84→          {/* Brand Logo */}
 85→          <Link href="/" className="flex-shrink-0">
 86→            <Image
 87→              src="/logo/image.png"
 88→              alt="Zenith Trends"
 89→              width={180}
 90→              height={50}
 91→              className="h-10 w-auto sm:h-12 lg:h-14"
 92→              priority
 93→            />
 94→          </Link>
 95→
 96→          {/* Desktop Navigation */}
 97→          <nav className="hidden lg:flex lg:items-center lg:gap-1">
 98→            {navLinks.map((link) =>
 99→              link.hasDropdown ? (
100→                <div
101→                  key={link.label}
102→                  className="relative"
103→                  onMouseEnter={() => setProductsOpen(true)}
104→                  onMouseLeave={() => setProductsOpen(false)}
105→                >
106→                  <Link
107→                    href={link.href}
108→                    className="flex items-center gap-1 rounded-lg px-4 py-2 text-sm font-medium text-slate-700 transition-colors hover:bg-[#F5F3FF] hover:text-[#6D28D9]"
109→                  >
110→                    {link.label}
111→                    <ChevronDown
112→                      className={`h-4 w-4 transition-transform duration-200 ${
113→                        productsOpen ? "rotate-180" : ""
114→                      }`}
115→                    />
116→                  </Link>
117→                  <AnimatePresence>
118→                    {productsOpen && (
119→                      <motion.div
120→                        initial={{ opacity: 0, y: 8 }}
121→                        animate={{ opacity: 1, y: 0 }}
122→                        exit={{ opacity: 0, y: 8 }}
123→                        transition={{ duration: 0.2 }}
124→                        className="absolute left-0 top-full z-50 w-[540px] rounded-xl border border-slate-100 bg-white p-2 shadow-xl shadow-black/8"
125→                      >
126→                        <div className="grid max-h-[70vh] grid-cols-2 gap-x-1 overflow-y-auto">
127→                          {categories.map((cat) => (
128→                            <Link
129→                              key={cat.slug}
130→                              href={`/products/${cat.slug}`}
131→                              className="flex items-center justify-between rounded-lg px-3 py-2 text-sm text-slate-600 transition-colors hover:bg-[#F5F3FF] hover:text-[#6D28D9]"
132→                            >
133→                              <span className="truncate">{cat.name}</span>
134→                              <span className="ml-2 flex-shrink-0 rounded-full bg-slate-100 px-2 py-0.5 text-xs text-slate-500">
135→                                {cat.productCount}
136→                              </span>
137→                            </Link>
138→                          ))}
139→                        </div>
140→                      </motion.div>
141→                    )}
142→                  </AnimatePresence>
143→                </div>
144→              ) : link.label === "Sale" ? (
145→                <Link
146→                  key={link.label}
147→                  href={link.href}
148→                  className="rounded-lg px-4 py-2 text-sm font-semibold text-rose-500 transition-colors hover:bg-rose-50"
149→                >
150→                  {link.label}
151→                </Link>
152→              ) : link.label === "New" ? (
153→                <Link
154→                  key={link.label}
155→                  href={link.href}
156→                  className="flex items-center gap-1 rounded-lg px-4 py-2 text-sm font-semibold text-[#7C3AED] transition-colors hover:bg-[#F5F3FF]"
157→                >
158→                  {link.label}
159→                  <span className="rounded-full bg-[#7C3AED] px-1.5 py-0.5 text-[9px] font-bold text-white leading-none">&#10022;</span>
160→                </Link>
161→              ) : (
162→                <Link
163→                  key={link.label}
164→                  href={link.href}
165→                  className="rounded-lg px-4 py-2 text-sm font-medium text-slate-700 transition-colors hover:bg-[#F5F3FF] hover:text-[#6D28D9]"
166→                >
167→                  {link.label}
168→                </Link>
169→              )
170→            )}
171→          </nav>
172→
173→          {/* Right Actions */}
174→          <div className="flex items-center gap-2">
175→            {/* Search Toggle */}
176→            <button
177→              onClick={() => setSearchOpen(!searchOpen)}
178→              className="rounded-lg p-2 text-slate-600 transition-colors hover:bg-slate-100 hover:text-[#7C3AED]"
179→              aria-label="Search"
180→            >
181→              <Search className="h-5 w-5" />
182→            </button>
183→
184→            {/* Quote List Icon */}
185→            <button
186→              onClick={openDrawer}
187→              className="relative rounded-lg p-2 text-slate-600 transition-colors hover:bg-slate-100 hover:text-[#7C3AED]"
188→              aria-label={`Quote list — ${totalItems} items`}
189→            >
190→              <ShoppingBag className="h-5 w-5" />
191→              {totalItems > 0 && (
192→                <span className="absolute -right-0.5 -top-0.5 flex h-4.5 w-4.5 items-center justify-center rounded-full bg-[#D4A853] text-[9px] font-bold text-white shadow-sm">
193→                  {totalItems > 99 ? "99+" : totalItems}
194→                </span>
195→              )}
196→            </button>
197→
198→            {/* Request Quote CTA (desktop) */}
199→            <Link
200→              href="/contact"
201→              className="hidden rounded-lg bg-[#C62828] px-5 py-2.5 text-sm font-semibold text-white transition-all hover:bg-[#B71C1C] lg:inline-flex"
202→            >
203→              Get a Quote
204→            </Link>
205→
206→            {/* Mobile Menu Toggle */}
207→            <button
208→              onClick={() => setMobileOpen(!mobileOpen)}
209→              className="rounded-lg p-2 text-slate-600 transition-colors hover:bg-slate-100 lg:hidden"
210→              aria-label={mobileOpen ? "Close menu" : "Open menu"}
211→            >
212→              {mobileOpen ? (
213→                <X className="h-6 w-6" />
214→              ) : (
215→                <Menu className="h-6 w-6" />
216→              )}
217→            </button>
218→          </div>
219→        </div>
